const body = $input.item.json.body || {};
const filters = body.filters || {};
const page = body.page || 1;
const limit = body.limit || 10;
const offset = (page - 1) * limit;
const conditions = [];
const params = [];
if (filters.searchText && typeof filters.searchText === 'string' && filters.searchText.trim() !== '') {
  conditions.push(`(CONCAT(t.nombre, ' ', t.primer_apellido, ' ', COALESCE(t.segundo_apellido,'')) ILIKE $${params.length + 1} OR t.email ILIKE $${params.length + 1} OR t.dni_nif_pasaporte ILIKE $${params.length + 1})`);
  params.push(`%${filters.searchText.trim()}%`);
}
if (filters.status !== undefined && filters.status !== null && filters.status !== '') {
  const s = String(filters.status).toLowerCase();
  if (s !== 'todos' && s !== '') { conditions.push(`t.activo = $${params.length + 1}`); params.push(s === 'activo' || s === 'activos'); }
}
if (filters.tipo !== undefined && filters.tipo !== null && filters.tipo !== '') {
  const tp = String(filters.tipo).toLowerCase();
  if (tp === 'freelance') { conditions.push(`t.freelance = $${params.length + 1}`); params.push(true); }
  else if (tp === 'plantilla') { conditions.push(`t.freelance = $${params.length + 1}`); params.push(false); }
}
let whereClause = 'WHERE 1=1';
if (conditions.length > 0) whereClause += ' AND ' + conditions.join(' AND ');
const lp = params.length + 1;
const op = params.length + 2;
params.push(limit);
params.push(offset);
const query = `WITH global_stats AS (SELECT COUNT(*)::int as total, COUNT(*) FILTER (WHERE activo=true)::int as activos, COUNT(*) FILTER (WHERE activo=false)::int as inactivos, COUNT(*) FILTER (WHERE freelance=true)::int as freelances FROM trabajador), filtered_data AS (SELECT t.*, p.provincia AS provincia_nombre, l.localidad AS localidad_nombre, CONCAT(s.nombre,' ',s.primer_apellido) AS seleccionador_nombre FROM trabajador t LEFT JOIN provincia p ON t.id_provincia=p.id LEFT JOIN localidad l ON t.id_localidad=l.id LEFT JOIN seleccionadores s ON t.id_seleccionadores=s.id ${whereClause} ORDER BY t.id DESC LIMIT $${lp} OFFSET $${op}), filtered_count AS (SELECT COUNT(*)::int as total_filtered FROM trabajador t ${whereClause}) SELECT fd.*, fc.total_filtered, gs.total as stats_total, gs.activos as stats_activos, gs.inactivos as stats_inactivos, gs.freelances as stats_freelances FROM global_stats gs CROSS JOIN filtered_count fc LEFT JOIN filtered_data fd ON true`;
return [{ json: { query, params } }];
